import{_ as a,o as n,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"Installing Diamond Analytics on Your Phone","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/installing-pwa.md","filePath":"getting-started/installing-pwa.md"}'),e={name:"getting-started/installing-pwa.md"};function r(l,o,s,d,g,p){return n(),t("div",null,[...o[0]||(o[0]=[i('<h1 id="installing-diamond-analytics-on-your-phone" tabindex="-1">Installing Diamond Analytics on Your Phone <a class="header-anchor" href="#installing-diamond-analytics-on-your-phone" aria-label="Permalink to &quot;Installing Diamond Analytics on Your Phone&quot;">​</a></h1><p>Diamond Analytics is a Progressive Web App (PWA) — it installs directly from your browser without going through the App Store or Google Play.</p><h2 id="android-installation-chrome" tabindex="-1">Android Installation (Chrome) <a class="header-anchor" href="#android-installation-chrome" aria-label="Permalink to &quot;Android Installation (Chrome)&quot;">​</a></h2><ol><li>Open <strong>Chrome</strong> on your Android device</li><li>Go to <a href="https://diamondanalytics.app" target="_blank" rel="noreferrer">diamondanalytics.app</a></li><li>Tap the <strong>three dots menu</strong> in the top right</li><li>Tap <strong>Add to Home Screen</strong></li><li>Tap <strong>Add</strong></li></ol><p>Diamond Analytics now appears on your home screen and opens like a native app.</p><h2 id="ios-installation-safari" tabindex="-1">iOS Installation (Safari) <a class="header-anchor" href="#ios-installation-safari" aria-label="Permalink to &quot;iOS Installation (Safari)&quot;">​</a></h2><blockquote><p><strong>Important:</strong> You must use Safari on iOS. Chrome on iOS does not support PWA installation.</p></blockquote><ol><li>Open <strong>Safari</strong> on your iPhone or iPad</li><li>Go to <a href="https://diamondanalytics.app" target="_blank" rel="noreferrer">diamondanalytics.app</a></li><li>Tap the <strong>Share button</strong> (box with arrow at the bottom of the screen)</li><li>Scroll down and tap <strong>Add to Home Screen</strong></li><li>Tap <strong>Add</strong></li></ol><h2 id="optimizing-voice-logging-on-android" tabindex="-1">Optimizing Voice Logging on Android <a class="header-anchor" href="#optimizing-voice-logging-on-android" aria-label="Permalink to &quot;Optimizing Voice Logging on Android&quot;">​</a></h2><p>For the best voice logging experience, set Google Voice Typing as your default keyboard:</p><ol><li>Go to <strong>Settings → General Management → Keyboard list and default</strong></li><li>Set <strong>Google Voice Typing</strong> as your default input method</li></ol><p>After this one-time setup the microphone icon is always one tap away in the keyboard.</p>',12)])])}const m=a(e,[["render",r]]);export{c as __pageData,m as default};
